args.sparql:
SELECT DISTINCT ?attendance 
WHERE {
  { # NLCS
    ?series wdt:P31 wd:Q19308089; 
            wdt:P585 ?seriesDate;
            wdt:P527 ?game.
    ?game wdt:P118 wd:Q213252.
    ?game wdt:P1175 ?attendance.
    FILTER (YEAR(?seriesDate) IN (1982, 2006, 2011, 2013))
  }
  UNION
  { # World Series
    ?series wdt:P31 wd:Q655671;
            wdt:P585 ?seriesDate;
            wdt:P527 ?game.
    ?game wdt:P118 wd:Q213252.
    ?game wdt:P1175 ?attendance.
    FILTER (YEAR(?seriesDate) = 2011)
  }
}
ORDER BY DESC(?attendance)
LIMIT 5

